const LIGHT_THEME='light';const DARK_THEME='dark';function getValidThemeFromStorage(){let theme=localStorage.getItem('docs-theme')||LIGHT_THEME;return(theme===LIGHT_THEME||theme===DARK_THEME)?theme:LIGHT_THEME}
function bgOnLoad(){let theme=getValidThemeFromStorage();let currentTheme=$('head link#theme').attr('href');let storedTheme='static/css/'+theme+'.css';if(currentTheme!==storedTheme){$('head link#theme').attr('href','static/css/'+theme+'.css')}}
function fabOnClick(){let theme=getValidThemeFromStorage();let newTheme=(theme===DARK_THEME)?LIGHT_THEME:DARK_THEME;$('head link#theme').attr('href','static/css/'+newTheme+'.css');localStorage.setItem('docs-theme',newTheme)}